 1	import React, { FC, PropsWithChildren, ReactNode } from 'react';
 2	
 3	import { Tooltip } from '@patternfly/react-core';
 4	
 5	import EditButton from './EditButton';
 6	
 7	type EditButtonWithTooltipProps = PropsWithChildren<{
 8	  isEditable: boolean;
 9	  onEditClick: () => void;
10	  testId: string;
11	  tooltipContent?: ReactNode;
12	}>;
13	
14	const EditButtonWithTooltip: FC<EditButtonWithTooltipProps> = ({
15	  children,
16	  isEditable,
17	  tooltipContent,
18	  ...rest
19	}) => {
20	  if (!isEditable && tooltipContent) {
21	    return (
22	      <Tooltip content={tooltipContent}>
23	        <EditButton {...rest} isEditable={isEditable}>
24	          {children}
25	        </EditButton>
26	      </Tooltip>
27	    );
28	  }
29	
30	  return (
31	    <EditButton {...rest} isEditable={isEditable}>
32	      {children}
33	    </EditButton>
34	  );
35	};
36	
37	export default EditButtonWithTooltip;

